def process_response(self, request, response):
        if (
            self.sts_seconds
            and request.is_secure()
            and "Strict-Transport-Security" not in response
        ):
            sts_header = "max-age=%s" % self.sts_seconds
            if self.sts_include_subdomains:
                sts_header += "; includeSubDomains"
            if self.sts_preload:
                sts_header += "; preload"
            response.headers["Strict-Transport-Security"] = sts_header

        if self.content_type_nosniff:
            response.headers.setdefault("X-Content-Type-Options", "nosniff")

        if self.referrer_policy:
            # Support a comma-separated string or iterable of values to allow
            # fallback.
            response.headers.setdefault(
                "Referrer-Policy",
                ",".join(
                    [v.strip() for v in self.referrer_policy.split(",")]
                    if isinstance(self.referrer_policy, str)
                    else self.referrer_policy
                ),
            )

        if self.cross_origin_opener_policy:
            response.setdefault(
                "Cross-Origin-Opener-Policy",
                self.cross_origin_opener_policy,
            )
        return response

class TextBlock(FieldBlock):
    def __init__(
        self,
        required=True,
        help_text=None,
        rows=1,
        max_length=None,
        min_length=None,
        search_index=True,
        validators=(),
        **kwargs,
    ):
        self.field_options = {
            "required": required,
            "help_text": help_text,
            "max_length": max_length,
            "min_length": min_length,
            "validators": validators,
        }
        self.rows = rows
        self.search_index = search_index
        super().__init__(**kwargs)

    @cached_property
    def field(self):
        from wagtail.admin.widgets import AdminAutoHeightTextInput

        field_kwargs = {"widget": AdminAutoHeightTextInput(attrs={"rows": self.rows})}
        field_kwargs.update(self.field_options)
        return forms.CharField(**field_kwargs)

    def get_searchable_content(self, value):
        return [force_str(value)] if self.search_index else []

def to_internal_value(self, data):
        request = self.context.get('request')
        try:
            http_prefix = data.startswith(('http:', 'https:'))
        except AttributeError:
            self.fail('incorrect_type', data_type=type(data).__name__)

        if http_prefix:
            # If needed convert absolute URLs to relative path
            data = parse.urlparse(data).path
            prefix = get_script_prefix()
            if data.startswith(prefix):
                data = '/' + data[len(prefix):]

        data = uri_to_iri(parse.unquote(data))

        try:
            match = resolve(data)
        except Resolver404:
            self.fail('no_match')

        try:
            expected_viewname = request.versioning_scheme.get_versioned_viewname(
                self.view_name, request
            )
        except AttributeError:
            expected_viewname = self.view_name

        if match.view_name != expected_viewname:
            self.fail('incorrect_match')

        try:
            return self.get_object(match.view_name, match.args, match.kwargs)
        except (ObjectDoesNotExist, ObjectValueError, ObjectTypeError):
            self.fail('does_not_exist')

def resolve_user_email(root: SyncWebhookControlContext[models.Order], info):
        order = root.node

        def _resolve_user_email(user):
            requester = get_user_or_app_from_context(info.context)
            email_to_return = None
            if order.user_email:
                email_to_return = order.user_email
            elif user:
                email_to_return = user.email

            if order.use_old_id is False:
                return email_to_return
            if user and is_owner_or_has_one_of_perms(
                requester, user, OrderPermissions.MANAGE_ORDERS
            ):
                return email_to_return

            return obfuscate_email(email_to_return)

        if not order.user_id:
            return _resolve_user_email(None)

        return (
            UserByUserIdLoader(info.context)
            .load(order.user_id)
            .then(_resolve_user_email)
        )

def get_content_access_streams(
    user_profile: UserProfile,
    streams: Collection[Stream],
    user_group_membership_details: UserGroupMembershipDetails,
) -> list[Stream]:
    if len(streams) == 0:
        return []

    recipient_ids = [stream.recipient_id for stream in streams]
    subscribed_recipient_ids = set(
        Subscription.objects.filter(
            user_profile=user_profile, recipient_id__in=recipient_ids, active=True
        ).values_list("recipient_id", flat=True)
    )

    content_access_streams: list[Stream] = []

    for stream in streams:
        is_subscribed = stream.recipient_id in subscribed_recipient_ids
        if user_has_content_access(
            user_profile,
            stream,
            user_group_membership_details,
            is_subscribed=is_subscribed,
        ):
            content_access_streams.append(stream)

    return content_access_streams

def engagement_calendar(request):

    if not get_system_setting("enable_calendar"):
        raise Resolver404

    if "lead" not in request.GET or "0" in request.GET.getlist("lead"):
        engagements = get_authorized_engagements("view")
    else:
        filters = []
        leads = request.GET.getlist("lead", "")
        if "-1" in request.GET.getlist("lead"):
            leads.remove("-1")
            filters.append(Q(lead__isnull=True))
        filters.append(Q(lead__in=leads))
        engagements = get_authorized_engagements("view").filter(reduce(operator.or_, filters))

    engagements = engagements.select_related("lead")
    engagements = engagements.prefetch_related("product")

    for e in engagements:
        if e.target_end:
            e.target_end += timedelta(days=1)
    add_breadcrumb(
        title="Engagement Calendar", top_level=True, request=request)
    return render(
        request, "dojo/calendar.html", {
            "caltype": "engagements",
            "leads": request.GET.getlist("lead", ""),
            "engagements": engagements,
            "users": get_authorized_users("view"),
        })

def create_questionnaire(request):
    form = CreateQuestionnaireForm()
    survey = None

    if request.method == "POST":
        form = CreateQuestionnaireForm(request.POST)
        if form.is_valid():
            survey = form.save()
            messages.add_message(
                request,
                messages.SUCCESS,
                "Questionnaire successfully created, you may now add questions.",
                extra_tags="alert-success")
            if "add_questions" in request.POST:
                return HttpResponseRedirect(reverse("edit_questionnaire_questions", args=(survey.id,)))
            return HttpResponseRedirect(reverse("questionnaire"))
        messages.add_message(
            request,
            messages.ERROR,
            "Please correct any errors displayed below.",
            extra_tags="alert-danger")

    add_breadcrumb(title="Create Questionnaire", top_level=False, request=request)
    return render(request, "defectDojo-engagement-survey/create_questionnaire.html", {
        "survey": survey,
        "form": form,
        "name": "Create Survey",
    })

def to_internal_value(self, value):
        input_formats = getattr(self, 'input_formats', api_settings.DATE_INPUT_FORMATS)

        if isinstance(value, datetime.datetime):
            self.fail('datetime')

        if isinstance(value, datetime.date):
            return value

        for input_format in input_formats:
            if input_format.lower() == ISO_8601:
                try:
                    parsed = parse_date(value)
                except (ValueError, TypeError):
                    pass
                else:
                    if parsed is not None:
                        return parsed
            else:
                try:
                    parsed = self.datetime_parser(value, input_format)
                except (ValueError, TypeError):
                    pass
                else:
                    return parsed.date()

        humanized_format = humanize_datetime.date_formats(input_formats)
        self.fail('invalid', format=humanized_format)

def get(self, request, *_, **kwargs):
        request_id = kwargs.get('request_id')
        profile_id = kwargs.get('profile_id')
        try:
            per_page = int(request.GET.get('per_page', self.default_page_size))
        except (TypeError, ValueError):
            per_page = self.default_page_size
        context = {
            'request': request,
            'options_page_size': self.page_sizes,
            'per_page': per_page,
        }
        if request_id:
            silk_request = Request.objects.get(id=request_id)
            query_set = SQLQuery.objects.filter(request=silk_request).order_by('-start_time')
            for q in query_set:
                q.start_time_relative = q.start_time - silk_request.start_time
            page = _page(request, query_set, per_page)
            context['silk_request'] = silk_request
        if profile_id:
            p = Profile.objects.get(id=profile_id)
            page = _page(request, p.queries.order_by('-start_time').all(), per_page)
            context['profile'] = p
        if not (request_id or profile_id):
            raise KeyError('no profile_id or request_id')
        # noinspection PyUnboundLocalVariable
        context['items'] = page
        return render(request, 'silk/sql.html', context)

def get_documents(self):
        WorkflowInstanceLogEntry = apps.get_model(
            app_label='document_states',
            model_name='WorkflowInstanceLogEntry'
        )

        latest_entries = WorkflowInstanceLogEntry.objects.annotate(
            max_datetime=Max(
                'workflow_instance__log_entries__datetime'
            )
        ).filter(
            datetime=F('max_datetime')
        )

        state_latest_entries = latest_entries.filter(
            transition__destination_state=self
        )

        return Document.valid.filter(
            Q(
                workflows__pk__in=state_latest_entries.values_list(
                    'workflow_instance', flat=True
                )
            ) | Q(
                workflows__log_entries__isnull=True,
                workflows__workflow__states=self,
                workflows__workflow__states__initial=True
            )
        ).distinct()

async def view_with_pagination(request: HttpRequest, **kwargs: Any) -> Any:
            pagination_params = kwargs.pop("ninja_pagination", None)
            if pagination_params is None:
                pagination_params = paginator.Input()
            if paginator.pass_parameter:
                kwargs[paginator.pass_parameter] = pagination_params

            items = await func(request, **kwargs)

            status_code = None
            if isinstance(items, Status):
                status_code = items.status_code
                items = items.value

            result = await paginator.apaginate_queryset(
                items, pagination=pagination_params, request=request, **kwargs
            )

            async def evaluate(results: Union[List, QuerySet]) -> AsyncGenerator:
                for result in results:
                    yield result

            if paginator.Output:  # type: ignore
                result[paginator.items_attribute] = [
                    result
                    async for result in evaluate(result[paginator.items_attribute])
                ]

            if status_code is not None:
                return Status(status_code, result)
            return result

def remove_workflow(request, page_pk, workflow_pk=None):
    # Remove a workflow from a page (specifically a single workflow if workflow_pk is set)
    # Get the page
    page = get_object_or_404(Page, id=page_pk)

    # Check permissions
    if not workflow_permission_policy.user_has_permission(request.user, "change"):
        raise PermissionDenied

    if hasattr(page, "workflowpage"):
        # If workflow_pk is set, this will only remove the workflow if it its pk matches - this prevents accidental
        # removal of the wrong workflow via a workflow edit page if the page listing is out of date
        if not workflow_pk or workflow_pk == page.workflowpage.workflow.pk:
            page.workflowpage.delete()
            messages.success(
                request,
                _("Workflow removed from Page '%(page_title)s'.")
                % {"page_title": page.get_admin_display_title()},
            )

    # Redirect
    redirect_to = request.POST.get("next", None)
    if redirect_to and url_has_allowed_host_and_scheme(
        url=redirect_to, allowed_hosts={request.get_host()}
    ):
        return redirect(redirect_to)
    else:
        return redirect("wagtailadmin_explore", page.id)

def _run_synchronous_transition(self, form):
        status, attachments = run_transition(
            instances=self.objects,
            transition_obj_or_name=self.transition,
            field=self.transition.model.field_name,
            data=form.cleaned_data if form else {},
            requester=self.request.user,
        )
        if status:
            messages.success(self.request, _("Transitions performed successfully"))
        else:
            messages.error(
                self.request,
                _(
                    (
                        "Something went wrong while displaying this transition. "
                        "To continue, reload or go to another transition."
                    )
                ),
            )
            return self.form_invalid(form)
        if attachments:
            urls = [
                reverse(
                    "serve_attachment",
                    args=(attachment.id, attachment.original_filename),
                )
                for attachment in attachments
            ]
            self.request.session["attachments_to_download"] = urls
        return HttpResponseRedirect(self.get_success_url())

class StoredDebugToolbar(DebugToolbar):
    def __init__(
        self,
        request: HttpRequest | None,
        get_response: GetResponse,
        request_id: str | None = None,
    ):
        self.request = None
        self.config = dt_settings.get_config().copy()
        self.process_request = get_response
        self.stats = {}
        self.server_timing_stats = {}
        self.request_id = request_id
        self.init_store()

    @classmethod
    def from_store(
        cls, request_id: str, panel_id: str | None = None
    ) -> StoredDebugToolbar:
        toolbar = StoredDebugToolbar(
            None, from_store_get_response, request_id=request_id
        )
        toolbar._panels = {}

        for panel_class in reversed(cls.get_panel_classes()):
            panel = panel_class(toolbar, from_store_get_response)
            if panel_id and panel.panel_id != panel_id:
                continue
            data = toolbar.store.panel(toolbar.request_id, panel.panel_id)
            panel.load_stats_from_store(data)
            toolbar._panels[panel.panel_id] = panel
        return toolbar

def create(client: Client, code: dict[str, Any], request: Request) -> None:
    adapter = get_adapter()
    ctx = get_validator_context()
    authorization_code = {
        "code": code,
        "client_id": client.id,
        "redirect_uri": request.redirect_uri,
        "sub": adapter.get_user_sub(client, request.user),
        "scopes": request.scopes,
        "claims": request.claims,
        "resources": ctx.requested_resources,
    }
    if email := ctx.email:
        # Don't trouble ourselves with keeping track a specific email in case
        # the primary was chosen.
        if EmailAddress.objects.get_primary_email(request.user) != email.lower():
            authorization_code["email"] = email
    code_challenge = getattr(request, "code_challenge", None)
    if code_challenge:
        authorization_code["pkce"] = {
            "code_challenge": code_challenge,
            "code_challenge_method": request.code_challenge_method,
        }
    cache.set(
        cache_key(client.id, code["code"]),
        authorization_code,
        timeout=app_settings.AUTHORIZATION_CODE_EXPIRES_IN,
    )

def get_form_options(self):
        if self.read_only:
            return {}

        opts = {
            "fields": [self.field_name],
        }

        required_on_save = self.required_on_save
        if required_on_save is None:
            # If required_on_save is not explicitly set, treat it as false unless:
            # - it corresponds to a model field with required_on_save=True (such as page title)
            # - it corresponds to a non-null, non-text-typed model field (in which case a blank value
            #   is not valid at the database level)
            try:
                db_field = self.db_field
            except FieldDoesNotExist:
                required_on_save = False
            else:
                required_on_save = getattr(db_field, "required_on_save", False) or (
                    db_field.null is False
                    and db_field.get_internal_type()
                    not in ("CharField", "TextField", "JSONField")
                )

        if not required_on_save:
            opts["defer_required_on_fields"] = [self.field_name]

        if self.widget:
            opts["widgets"] = {self.field_name: self.widget}

        if self.permission:
            opts["field_permissions"] = {self.field_name: self.permission}

        return opts

@cached_property
    def panel_definitions(self):
        # Look for a panels definition in the InlinePanel declaration
        if self.panels is not None:
            return self.panels
        # Failing that, get it from the model
        return extract_panel_definitions_from_model_class(
            self.db_field.related_model, exclude=[self.db_field.field.name]
        )

    @cached_property
    def child_edit_handler(self):
        panels = self.panel_definitions
        child_edit_handler = MultiFieldPanel(panels, heading=self.heading)
        return child_edit_handler.bind_to_model(self.db_field.related_model)

    def get_form_options(self):
        child_form_opts = self.child_edit_handler.get_form_options()

        formset_opts = {
            "fields": child_form_opts.get("fields", []),
            "widgets": child_form_opts.get("widgets", {}),
            "min_num": self.min_num,
            "validate_min": self.min_num is not None,
            "max_num": self.max_num,
            "validate_max": self.max_num is not None,
            "formsets": child_form_opts.get("formsets"),
        }

def handle(self, **kwargs):
        feed_urls = set(
            Feed.objects.filter(approval_status=APPROVED_FEED).values_list(
                "feed_url", flat=True
            )
        )

        subscribed_urls = set(Subscription.objects.values_list("topic", flat=True))

        missing_feeds = feed_urls - subscribed_urls
        extra_feeds = subscribed_urls - feed_urls

        for url in missing_feeds:
            logger.info(f"Subscribing to {url}")
            Subscription.objects.subscribe(url, settings.PUSH_HUB)

        for subscription in Subscription.objects.filter(topic__in=extra_feeds):
            logger.info(f"Unsubscribing from {subscription.pk} ({subscription.topic})")
            subscription.unsubscribe()

        limit = timezone.now() + timedelta(days=2)
        for subscription in Subscription.objects.exclude(topic__in=extra_feeds).filter(
            lease_expiration__lte=limit
        ):
            logger.info(
                f"Renewing subscription for {subscription.topic} ({subscription.pk})"
            )
            subscription.subscribe()
